  v_processed   		CHAR(1);
  v_check_from  		VARCHAR2(200);
  v_check_up 			VARCHAR2(200);
  v_ssfi_banktransfer_id 	VARCHAR2(34);
  vAux NUMBER;
BEGIN

    IF AD_isTriggerEnabled()='N' THEN RETURN;
    END IF;

 --Check if trying to move object from module not in dev
  IF (INSERTING) THEN
	Select 		check_from 	,check_up	,ssfi_banktransfer_id	, COALESCE(process,'N')
		Into 	v_check_from 	,v_check_up	,v_ssfi_banktransfer_id , v_processed
	From sspch_postdated_checks   
	Where sspch_postdated_checks_id = :NEW.sspch_postdated_checks_id;
	If(v_processed = 'Y')Then
		RAISE_APPLICATION_ERROR(-20000, '@DocBeingProcessed@');
	End IF;
	Select COUNT(*) 
		Into vAux
	From sspch_postdated_checks  spc
		join sspch_invoice  si on si.sspch_postdated_checks_id = spc.sspch_postdated_checks_id
	Where spc.check_from = v_check_from
		And spc.check_up = v_check_up
		And spc.ssfi_banktransfer_id = v_ssfi_banktransfer_id
		And si.c_invoice_id  = :NEW.c_invoice_id;
	If(vAux>0)Then
		RAISE_APPLICATION_ERROR(-20000, '@Sspch_Duplicated@');
	End IF;
  END IF;

END SSPCH_DUPLICATED_TRG
